import{_ as a,c as e,l as s,a as l,t as p,a4 as i,o as r}from"./chunks/framework.CzsDe1xi.js";const E=JSON.parse('{"title":"Binlog","description":"","frontmatter":{"title":"Binlog"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/日志/Binlog/Binlog详解.md","filePath":"packages/doc/src/数据库/Mysql/基础/日志/Binlog/Binlog详解.md","lastUpdated":1711354439000}'),o={name:"doc/数据库/Mysql/基础/日志/Binlog/Binlog详解.md"},b={id:"frontmatter-title",tabindex:"-1"},t=s("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),c=i(`<h2 id="_1-binlog记录了对表数据和结构的更改操作信息等-言外之意不会存储select-show等查询语句信息" tabindex="-1">1.Binlog记录了对表数据和结构的更改操作信息等，言外之意不会存储select，show等查询语句信息 <a class="header-anchor" href="#_1-binlog记录了对表数据和结构的更改操作信息等-言外之意不会存储select-show等查询语句信息" aria-label="Permalink to &quot;1.Binlog记录了对表数据和结构的更改操作信息等，言外之意不会存储select，show等查询语句信息&quot;">​</a></h2><h3 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h3><p>复制：主从服务器同步数据复制</p><p>崩溃恢复：某些数据恢复操作需要使用二进制日志。恢复备份后，将重新执行备份后记录的二进制日志中的事件。这些事件使数据库从备份点开始更新。</p><h3 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h3><ol><li><p>binlog 是 MySQL 的 Server 层实现的，所有引擎都可以使用。</p></li><li><p>binlog 是逻辑日志，记录的是这个语句的原始逻辑，比如“给 ID=2 这一行的 c 字段加 1”。</p></li><li><p>binlog 是可以追加写入的。“追加写”是指 binlog 文件写到一定大小后会切换到下一个，并不会覆盖以前的日志。</p></li></ol><h2 id="_2-如何启用" tabindex="-1">2.如何启用 <a class="header-anchor" href="#_2-如何启用" aria-label="Permalink to &quot;2.如何启用&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>log-bin=/var/lib/mysql/mysql-bin</span></span>
<span class="line"><span>binlog_format=ROW -- STATEMENT，ROW，MIXED</span></span>
<span class="line"><span>expire_logs_days=7</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span># 查看详细的日志配置信息</span></span>
<span class="line"><span>show global variables like &#39;%log%&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># mysql数据存储目录</span></span>
<span class="line"><span>show variables like &#39;%dir%&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看binlog的目录</span></span>
<span class="line"><span>show global variables like &quot;%log_bin%&quot;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看当前服务器使用的biglog文件及大小</span></span>
<span class="line"><span>show binary logs;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看主服务器使用的biglog文件及大小</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看最新一个binlog日志文件名称和Position</span></span>
<span class="line"><span>show master status;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span># 事件查询命令</span></span>
<span class="line"><span># IN &#39;log_name&#39; ：指定要查询的binlog文件名(不指定就是第一个binlog文件)</span></span>
<span class="line"><span># FROM pos ：指定从哪个pos起始点开始查起(不指定就是从整个文件首个pos点开始算)</span></span>
<span class="line"><span># LIMIT [offset,] ：偏移量(不指定就是0)</span></span>
<span class="line"><span># row_count ：查询总条数(不指定就是所有行)</span></span>
<span class="line"><span>show binlog events [IN &#39;log_name&#39;] [FROM pos] [LIMIT [offset,] row_count];</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看 binlog 内容</span></span>
<span class="line"><span>show binlog events;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看具体一个binlog文件的内容 （in 后面为binlog的文件名）</span></span>
<span class="line"><span>show binlog events in &#39;master.000003&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 设置binlog文件保存事件，过期删除，单位天</span></span>
<span class="line"><span>set global expire_log_days=3; </span></span>
<span class="line"><span></span></span>
<span class="line"><span># 删除当前的binlog文件</span></span>
<span class="line"><span>reset master; </span></span>
<span class="line"><span></span></span>
<span class="line"><span># 删除slave的中继日志</span></span>
<span class="line"><span>reset slave;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 删除指定日期前的日志索引中binlog日志文件</span></span>
<span class="line"><span>purge master logs before &#39;2019-03-09 14:00:00&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 删除指定日志文件</span></span>
<span class="line"><span>purge master logs to &#39;master.000003&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br></div></div><h2 id="_3-如何记录" tabindex="-1">3.如何记录 <a class="header-anchor" href="#_3-如何记录" aria-label="Permalink to &quot;3.如何记录&quot;">​</a></h2><p>binlog按事件的线性序列记录，修改数据库的sql将生成一个或多个事件并将其追加到binlog日志中，还有一些辅助事件类型描述了binlog的结构。记录在二进制日志中的事件的格式取决于二进制记录格式。支持三种格式类型：</p><p><strong>STATEMENT：基于SQL语句的复制（statement-based replication, SBR）</strong><strong>ROW：基于行的复制（row-based replication, RBR）</strong><strong>MIXED：混合模式复制（mixed-based replication, MBR）</strong> 在 MySQL 5.7.7 之前，默认的格式是 STATEMENT，在 MySQL 5.7.7 及更高版本中，默认值是 ROW。日志格式通过 binlog-format 指定，</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>如 binlog-format=STATEMENT、binlog-format=ROW、binlog-format=MIXED。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>show variables like &#39;%binlog_format%&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SET GLOBAL binlog_format = &#39;STATEMENT&#39;;</span></span>
<span class="line"><span>SET GLOBAL binlog_format = &#39;ROW&#39;;</span></span>
<span class="line"><span>SET GLOBAL binlog_format = &#39;MIXED&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>SET SESSION binlog_format = &#39;STATEMENT&#39;;</span></span>
<span class="line"><span>SET SESSION binlog_format = &#39;ROW&#39;;</span></span>
<span class="line"><span>SET SESSION binlog_format = &#39;MIXED&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>Before Image(前镜像) (BI) 且/或 After Image(后镜像) (AI)</p><p>日志的事件有三种类型： 1.Write_rows_log_event：向表中添加新行，只有AI 2.Update_rows_log_event：修改表中的现有行，BI和AI都有 3.Delete_rows_log_event：从表中删除现有行，只有BI</p><h3 id="statement-sbr" tabindex="-1">Statement(SBR) <a class="header-anchor" href="#statement-sbr" aria-label="Permalink to &quot;Statement(SBR)&quot;">​</a></h3><p>每一条会修改数据的sql语句会记录到binlog中。优点是并不需要记录每一条sql语句和每一行的数据变化，减少了binlog日志量，节约IO，提高性能。缺点是在某些情况下会导致master-slave中的数据不一致(如sleep()函数， last_insert_id()，以及user-defined functions(udf)等会出现问题)</p><h3 id="row-rbr" tabindex="-1">Row(RBR) <a class="header-anchor" href="#row-rbr" aria-label="Permalink to &quot;Row(RBR)&quot;">​</a></h3><p>不记录每条sql语句的上下文信息，仅需记录哪条数据被修改了，修改成什么样了。而且不会出现某些特定情况下的存储过程、或function、或trigger的调用和触发无法被正确复制的问题。缺点是会产生大量的日志，尤其是alter table的时候会让日志暴涨。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>update student set age = age+1 where id = 1;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>![image-20211123175414257](/Users/xulei/Library/Application Support/typora-user-images/image-20211123175414257.png)</p><h3 id="mixed" tabindex="-1">MIXED <a class="header-anchor" href="#mixed" aria-label="Permalink to &quot;MIXED&quot;">​</a></h3><p>以上两种模式的混合使用，一般的复制使用STATEMENT模式保存binlog，对于STATEMENT模式无法复制的操作使用ROW模式保存binlog，MySQL会根据执行的SQL语句选择日志保存方式。</p><h3 id="sbr-和-rbr-模式各自的优缺点" tabindex="-1">SBR 和 RBR 模式各自的优缺点： <a class="header-anchor" href="#sbr-和-rbr-模式各自的优缺点" aria-label="Permalink to &quot;SBR 和 RBR 模式各自的优缺点：&quot;">​</a></h3><p><strong>SBR 的优点：</strong></p><p>历史悠久，技术成熟 binlog文件较小 binlog中包含了所有<a href="http://www.111cn.net/database/database.html" target="_blank" rel="noreferrer">数据库</a>更改信息，可以据此来审核数据库的安全等情况 binlog可以用于实时的还原，而不仅仅用于复制 主从版本可以不一样，从服务器版本可以比主服务器版本高</p><p><strong>SBR 的缺点：</strong></p><p>不是所有的UPDATE语句都能被复制，尤其是包含不确定操作的时候。 调用具有不确定因素的 UDF 时复制也可能出问题 使用以下函数的语句也无法被复制： * LOAD_FILE() * UUID() * USER() * FOUND_ROWS() * SYSDATE() (除非启动时启用了 --sysdate-is-now 选项) INSERT ... SELECT 会产生比 RBR 更多的行级锁 复制需要进行全表扫描(WHERE 语句中没有使用到索引)的 UPDATE 时，需要比 RBR 请求更多的行级锁 对于有 AUTO_INCREMENT 字段的 InnoDB表而言，INSERT 语句会阻塞其他 INSERT 语句 对于一些复杂的语句，在从服务器上的耗资源情况会更严重，而 RBR 模式下，只会对那个发生变化的记录产生影响 存储函数(不是存储过程)在被调用的同时也会执行一次 NOW() 函数，这个可以说是坏事也可能是好事 确定了的 UDF 也需要在从服务器上执行 数据表必须几乎和主服务器保持一致才行，否则可能会导致复制出错 执行复杂语句如果出错的话，会消耗更多资源</p><p><strong>RBR 的优点：</strong></p><p>任何情况都可以被复制，这对复制来说是最安全可靠的 和其他大多数数据库系统的复制技术一样 多数情况下，从服务器上的表如果有主键的话，复制就会快了很多 复制以下几种语句时的行锁更少： * INSERT ... SELECT * 包含 AUTO_INCREMENT 字段的 INSERT * 没有附带条件或者并没有修改很多记录的 UPDATE 或 DELETE 语句 执行 INSERT，UPDATE，DELETE 语句时锁更少 从服务器上采用多线程来执行复制成为可能</p><p><strong>RBR 的缺点：</strong></p><p>binlog 大了很多 复杂的回滚时 binlog 中会包含大量的数据 主服务器上执行 UPDATE 语句时，所有发生变化的记录都会写到 binlog 中，而 SBR 只会写一次，这会导致频繁发生 binlog 的并发写问题 UDF 产生的大 BLOB 值会导致复制变慢 无法从 binlog 中看到都复制了写什么语句 当在非事务表上执行一段堆积的SQL语句时，最好采用 SBR 模式，否则很容易导致主从服务器的数据不一致情况发生</p><p>另外，针对系统库 mysql 里面的表发生变化时的处理规则如下： 如果是采用 INSERT，UPDATE，DELETE 直接操作表的情况，则日志格式根据 binlog_format 的设定而记录 如果是采用 GRANT，REVOKE，SET PASSWORD 等管理语句来做的话，那么无论如何都采用 SBR 模式记录 注：采用 RBR 模式后，能解决很多原先出现的主键重复问题。</p><h2 id="_4-mysqlbinlog工具" tabindex="-1">4.mysqlbinlog工具 <a class="header-anchor" href="#_4-mysqlbinlog工具" aria-label="Permalink to &quot;4.mysqlbinlog工具&quot;">​</a></h2><p>您可以使用<a href="https://dev.mysql.com/doc/refman/5.7/en/mysqlbinlog.html" target="_blank" rel="noreferrer"><strong>mysqlbinlog</strong></a>实用程序显示二进制日志文件的内容 。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>flush logs;</span></span>
<span class="line"><span>每次都会新生成一个bin log文件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysqlbinlog --no-defaults --base64-output=decode-rows ./mysql-bin.000001 | more</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="_5-日志文件" tabindex="-1">5.日志文件 <a class="header-anchor" href="#_5-日志文件" aria-label="Permalink to &quot;5.日志文件&quot;">​</a></h2><p>binlog日志包括两类文件:</p><ul><li>二进制日志索引文件（文件名后缀为.index）用于记录所有有效的的二进制文件</li><li>二进制日志文件（文件名后缀为.00000*）记录数据库所有的DDL和DML语句事件</li></ul><p>![image-20211123165404669](/Users/xulei/Library/Application Support/typora-user-images/image-20211123165404669.png)</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>sync_binlog 参数控制bin log什么时候持久化到磁盘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1.如果设置为0，则表示MySQL不控制binlog的刷新，由文件系统去控制它缓存的刷新；</span></span>
<span class="line"><span>2.如果设置为不为0的值，则表示每 sync_binlog 次事务，MySQL调用文件系统的刷新操作刷新binlog到磁盘中。</span></span>
<span class="line"><span>3.设为1是最安全的，在系统故障时最多丢失一个事务的更新，但是会对性能有所影响。</span></span>
<span class="line"><span>4.如果 sync_binlog=0 或 sync_binlog大于1，当发生电源故障或操作系统崩溃时，可能有一部分已提交但其binlog未被同步到磁盘的事务会被丢失，恢复程序将无法恢复这部分事务。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在MySQL 5.7.7之前，默认值 sync_binlog 是0，MySQL 5.7.7和更高版本使用默认值1，这是最安全的选择。一般情况下会设置为100或者0，牺牲一定的一致性来获取更好的性能。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>binlog是一个二进制文件集合，每个binlog文件以一个4字节的魔数开头，接着是一组Events:</p><p>魔数：0xfe62696e对应的是0xfebin； Event：每个Event包含header和data两个部分；header提供了Event的创建时间，哪个服务器等信息，data部分提供的是针对该Event的具体信息，如具体数据的修改； 第一个Event用于描述binlog文件的格式版本，这个格式就是event写入binlog文件的格式； 其余的Event按照第一个Event的格式版本写入； 最后一个Event用于说明下一个binlog文件； binlog的索引文件是一个文本文件，其中内容为当前的binlog文件列表</p><h3 id="_6-当遇到以下3种情况时-mysql会重新生成一个新的日志文件-文件序号递增" tabindex="-1">6.当遇到以下3种情况时，MySQL会重新生成一个新的日志文件，文件序号递增： <a class="header-anchor" href="#_6-当遇到以下3种情况时-mysql会重新生成一个新的日志文件-文件序号递增" aria-label="Permalink to &quot;6.当遇到以下3种情况时，MySQL会重新生成一个新的日志文件，文件序号递增：&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>1.MySQL服务器停止或重启时</span></span>
<span class="line"><span>2.使用 flush logs 命令；</span></span>
<span class="line"><span>3.当 binlog 文件大小超过 max_binlog_size 变量的值时；</span></span>
<span class="line"><span>max_binlog_size 的最小值是4096字节，最大值和默认值是 1GB (1073741824字节)。事务被写入到binlog的一个块中，所以它不会在几个二进制日志之间被拆分。因此，如果你有很大的事务，为了保证事务的完整性，不可能做切换日志的动作，只能将该事务的日志都记录到当前日志文件中，直到事务结束，你可能会看到binlog文件大于 max_binlog_size 的情况。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_7-如何删除binlog" tabindex="-1">7.如何删除binlog <a class="header-anchor" href="#_7-如何删除binlog" aria-label="Permalink to &quot;7.如何删除binlog&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>#删除mysql-bin.000003之前的所有binlog日志,不包括mysql-bin.000003</span></span>
<span class="line"><span>1.PURGE BINARY LOGS TO &#39;mysql-bin.000003&#39;;</span></span>
<span class="line"><span>#删除2019-01-30 10:53:26 这个日期之前的所有binlog日志</span></span>
<span class="line"><span>2.PURGE BINARY LOGS BEFORE &#39;2019-01-30 10:53:26&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#删除全部binlog日志，谨慎使用此语句</span></span>
<span class="line"><span>3.RESET MASTER</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div>`,49);function d(n,m,u,g,h,v){return r(),e("div",null,[s("h1",b,[l(p(n.$frontmatter.title)+" ",1),t]),c])}const S=a(o,[["render",d]]);export{E as __pageData,S as default};
